+// formatRecoveryError formats an error for logging.
+func formatRecoveryError(err *RecoveryError) string {
+	if err == nil {
+		return ""
+	}
+	return "[RECOVERY-ERROR] " + err.Code + ": " + err.Message + " (component: " + err.Component + ")"
